import ctypes
from ctypes import wintypes

def extract_paths_from_shell_idlist_array(data: bytes):
    shell32 = ctypes.windll.shell32

    # 函数声明
    ILCombine = shell32.ILCombine
    ILCombine.argtypes = [ctypes.c_void_p, ctypes.c_void_p]
    ILCombine.restype = ctypes.c_void_p

    SHGetPathFromIDListW = shell32.SHGetPathFromIDListW
    SHGetPathFromIDListW.argtypes = [ctypes.c_void_p, wintypes.LPWSTR]
    SHGetPathFromIDListW.restype = wintypes.BOOL

    ILFree = shell32.ILFree
    ILFree.argtypes = [ctypes.c_void_p]

    # 解析CIDA结构
    base = (ctypes.c_char * len(data)).from_buffer_copy(data)
    base_addr = ctypes.addressof(base)

    count = ctypes.c_uint.from_buffer_copy(data, 0).value
    offsets = (ctypes.c_uint * (count + 1)).from_buffer_copy(data, 4)

    root_offset = offsets[0]
    root_pidl = base_addr + root_offset

    paths = []
    for i in range(1, count + 1):
        child_offset = offsets[i]
        child_pidl = base_addr + child_offset

        # 组合根和子PIDL
        full_pidl = ILCombine(root_pidl, child_pidl)
        if full_pidl:
            buf = ctypes.create_unicode_buffer(1024)
            if SHGetPathFromIDListW(full_pidl, buf):
                if buf.value:
                    paths.append(buf.value)
            ILFree(full_pidl)

    return paths



print(extract_paths_from_shell_idlist_array(data))






import ctypes
from ctypes import wintypes

# Define the required Windows functions and their argument/return types
shell32 = ctypes.windll.shell32

# SHGetPathFromIDListW(PCIDLIST_ABSOLUTE pidl, LPWSTR pszPath)
SHGetPathFromIDListW = shell32.SHGetPathFromIDListW
SHGetPathFromIDListW.argtypes = [ctypes.c_void_p, wintypes.LPWSTR]
SHGetPathFromIDListW.restype = wintypes.BOOL

# ILCombine(PCIDLIST_ABSOLUTE pidlParent, PCUIDLIST_RELATIVE pidlChild)
ILCombine = shell32.ILCombine
ILCombine.argtypes = [ctypes.c_void_p, ctypes.c_void_p]
ILCombine.restype = ctypes.c_void_p  # Returns a new PIDLIST_ABSOLUTE

# ILFree(PIDLIST_ABSOLUTE pidl)
ILFree = shell32.ILFree
ILFree.argtypes = [ctypes.c_void_p]
ILFree.restype = None

def extract_paths_from_shell_idlist_array(data: bytes):
    """Parses CFSTR_SHELLIDLIST data structure and extracts file paths"""
    
    # Create a buffer from the data
    data_buf = ctypes.create_string_buffer(data)
    base_addr = ctypes.addressof(data_buf)
    
    # Get the count of child items (cidl)
    # The count is the first UINT at the base address
    count = ctypes.cast(base_addr, ctypes.POINTER(ctypes.c_uint))[0]
    
    # Get the offset array (aoffset)
    # It starts right after the count (sizeof(UINT))
    offset_array_ptr = ctypes.cast(base_addr + ctypes.sizeof(ctypes.c_uint), 
                                  ctypes.POINTER(ctypes.c_uint))
    
    paths = []
    
    # Get the parent folder's PIDL (always at offset[0])
    pidl_parent = base_addr + offset_array_ptr[0]
    
    # Loop ONLY for the child items (from 1 to count)
    for i in range(1, count + 1):
        # Get the child item's relative PIDL
        pidl_child = base_addr + offset_array_ptr[i]
        
        # Combine parent and child to get a full, absolute PIDL
        pidl_full = ILCombine(pidl_parent, pidl_child)
        
        if pidl_full:
            try:
                buf = ctypes.create_unicode_buffer(260)  # MAX_PATH
                if SHGetPathFromIDListW(pidl_full, buf):
                    path = buf.value
                    if path:
                        paths.append(path)
            finally:
                # IMPORTANT: Free the memory allocated by ILCombine
                ILFree(pidl_full)
                
    return paths

# Your provided data

paths = extract_paths_from_shell_idlist_array(data)
print("Extracted paths:", paths)







